@layer mergora.components {
  .mrg-table {
    max-inline-size: 100%;
    overflow: auto;
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
    scrollbar-gutter: stable;
  }
  .mrg-table:focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }
  .mrg-table table {
    inline-size: 100%;
    min-inline-size: 34rem;
    border-collapse: collapse;
    font-variant-numeric: tabular-nums;
  }
  .mrg-table caption {
    padding: var(--mrg-semantic-space-inset-md);
    text-align: start;
    font-size: var(--mrg-semantic-font-size-heading-small);
    font-weight: var(--mrg-semantic-font-weight-heading);
  }
  .mrg-table th,
  .mrg-table td {
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
    border-block-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    text-align: start;
    vertical-align: top;
  }
  .mrg-table thead th {
    color: var(--mrg-semantic-color-foreground-muted);
    background: var(--mrg-semantic-color-background-surface);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }
  .mrg-table [data-align="center"] {
    text-align: center;
  }
  .mrg-table [data-align="end"] {
    text-align: end;
  }
  .mrg-table__empty {
    padding-block: var(--mrg-semantic-space-stack-lg);
    color: var(--mrg-semantic-color-foreground-muted);
    text-align: center !important;
  }
  @media (max-width: 32rem) {
    .mrg-table[data-responsive-labels] table,
    .mrg-table[data-responsive-labels] tbody,
    .mrg-table[data-responsive-labels] tr,
    .mrg-table[data-responsive-labels] td,
    .mrg-table[data-responsive-labels] th {
      display: block;
      min-inline-size: 0;
    }
    .mrg-table[data-responsive-labels] thead {
      position: absolute;
      inline-size: 1px;
      block-size: 1px;
      overflow: hidden;
      clip-path: inset(50%);
    }
    .mrg-table[data-responsive-labels] tbody tr {
      padding: var(--mrg-semantic-space-inset-sm);
      border-block-start: var(--mrg-semantic-border-width-default) solid
        var(--mrg-semantic-color-border-strong);
    }
    .mrg-table[data-responsive-labels] tbody :is(td, th) {
      display: grid;
      grid-template-columns: minmax(7rem, 0.8fr) minmax(0, 1fr);
      gap: var(--mrg-semantic-space-inline-md);
      border: 0;
      padding-block: var(--mrg-semantic-space-inset-xs);
    }
    .mrg-table[data-responsive-labels] tbody :is(td, th)::before {
      content: attr(data-label);
      color: var(--mrg-semantic-color-foreground-muted);
      font-size: var(--mrg-semantic-font-size-label);
      font-weight: var(--mrg-semantic-font-weight-label);
    }
  }
  @media (forced-colors: active) {
    .mrg-table {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-table th,
    .mrg-table td {
      border-color: CanvasText;
    }
    .mrg-table:focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

import "./table.css";

import {
  forwardRef,
  type HTMLAttributes,
  type ReactElement,
  type ReactNode,
  type RefAttributes,
} from "react";

export interface TableColumn<TData extends object> {
  /** Stable column identity used as the React key. */
  readonly id: string;
  /** Visible column-header content and the source for optional responsive labels. */
  readonly header: ReactNode;
  /** Renders a cell value from its source row. */
  readonly cell: (row: TData) => ReactNode;
  /** Logical alignment applied consistently to the column header and body cells. */
  readonly align?: "start" | "center" | "end";
  /** Renders this column's body cells as scoped row headers. */
  readonly rowHeader?: boolean;
}

export interface TableProps<TData extends object> extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children"
> {
  /** Visible native table caption that identifies the tabular data. */
  readonly caption: ReactNode;
  /** Accessible name for the focusable overflow region surrounding the table. */
  readonly regionLabel: string;
  /** Ordered row models rendered into the table body. */
  readonly rows: readonly TData[];
  /** Ordered column definitions shared by the header and every row. */
  readonly columns: readonly TableColumn<TData>[];
  /** Returns a stable unique React key for a source row. */
  readonly getRowId: (row: TData) => string;
  /** Content spanning every column when rows is empty; defaults to No rows. */
  readonly emptyContent?: ReactNode;
  /** Adds data-label values for narrow-screen layouts; false omits those attributes. */
  readonly responsiveLabels?: boolean;
}

function classes(...values: readonly (string | undefined | false)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}

function TableInner<TData extends object>(
  {
    caption,
    regionLabel,
    rows,
    columns,
    getRowId,
    emptyContent = "No rows",
    responsiveLabels = false,
    className,
    ...props
  }: TableProps<TData>,
  ref: React.ForwardedRef<HTMLDivElement>,
): ReactElement {
  return (
    <div
      {...props}
      ref={ref}
      role="region"
      aria-label={regionLabel}
      tabIndex={0}
      className={classes("mrg-table", className)}
      data-slot="table-region"
      data-responsive-labels={responsiveLabels || undefined}
    >
      <table data-slot="table">
        <caption>{caption}</caption>
        <thead>
          <tr>
            {columns.map((column) => (
              <th key={column.id} scope="col" data-align={column.align ?? "start"}>
                {column.header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.length === 0 ? (
            <tr>
              <td className="mrg-table__empty" colSpan={Math.max(1, columns.length)}>
                {emptyContent}
              </td>
            </tr>
          ) : (
            rows.map((row) => (
              <tr key={getRowId(row)}>
                {columns.map((column) => {
                  const Element = column.rowHeader ? "th" : "td";
                  return (
                    <Element
                      key={column.id}
                      scope={column.rowHeader ? "row" : undefined}
                      data-align={column.align ?? "start"}
                      data-label={
                        responsiveLabels && typeof column.header === "string"
                          ? column.header
                          : undefined
                      }
                    >
                      {column.cell(row)}
                    </Element>
                  );
                })}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

/** Generic ref-aware call signature preserved by the forwarded Table implementation. */
export interface TableComponent {
  <TData extends object>(props: TableProps<TData> & RefAttributes<HTMLDivElement>): ReactElement;
}

export const Table = forwardRef(TableInner) as TableComponent;
